file_changes = {}

def remove_token(s, token):
    escaped = re.escape(token)
    pattern = r"(?<=[\s\"\'\`])" + escaped + r"(?=[\s\"\'\`])"
    return re.sub(pattern, '', s, count=1)

for p in problems:
    match = re.search(r"'([^']+)' applies the same CSS properties as '([^']+)'", p['message'])
    if not match:
        continue
    c1 = match.group(1)
    c2 = match.group(2)
    
    path = p['path']
    if path not in file_changes:
        with open(path, 'r', encoding='utf-8') as f:
            file_changes[path] = f.read().split('\\n')
            
    line_idx = p['startLine'] - 1
    
    # ensure it doesn't fail if the array isn't big enough
    if line_idx >= len(file_changes[path]):
        continue
        
    line = file_changes[path][line_idx]
    
    if c1 in line and c2 in line:
        if c1 == c2:
            line = remove_token(line, c1)
        else:
            line = remove_token(line, c1)
            
        line = re.sub(r'  +', ' ', line)
        file_changes[path][line_idx] = line

for path, lines in file_changes.items():
    with open(path, 'w', encoding='utf-8') as f:
        f.write('\\n'.join(lines))

print("Fixed")
